import{_ as t,o as i,c as r,ae as a}from"./chunks/framework.BivGZUvz.js";const h=JSON.parse('{"title":"Attribute registry","description":"","frontmatter":{},"headers":[],"relativePath":"registry/attributes/README.md","filePath":"registry/attributes/README.md"}'),n={name:"registry/attributes/README.md"};function o(s,e,l,c,d,p){return i(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="attribute-registry" tabindex="-1">Attribute registry <a class="header-anchor" href="#attribute-registry" aria-label="Permalink to &quot;Attribute registry&quot;">​</a></h1><p>The attributes registry is the place where attributes are defined. An attribute definition covers the following properties of an attribute:</p><ul><li>the <code>id</code> (the fully qualified name) of the attribute</li><li>the <code>type</code> of the attribute</li><li>the <code>stability</code> of the attribute</li><li>a <code>brief</code> description of the attribute and optionally a longer <code>note</code></li><li>example values</li></ul><p>Attributes defined in the registry can be used in different semantic conventions. Attributes should be included in this registry before they are used in semantic conventions. Semantic conventions may override all the properties of an attribute except for the <code>id</code>, <code>type</code> and <code>stability</code> in case it&#39;s required for a particular context. In addition, semantic conventions specify the requirement level of an attribute in the corresponding context.</p><p>A definition of an attribute in the registry doesn&#39;t necessarily imply that the attribute is used in any of the semantic conventions.</p><p>If applicable, application developers are encouraged to use existing attributes from this registry. See also <a href="./../../general/naming.html#recommendations-for-application-developers">these recommendations</a> regarding attribute selection and attribute naming for custom use cases.</p><p>All registered attributes are listed by namespace in this registry.</p><div class="warning custom-block github-alert"><p class="custom-block-title">WARNING</p><p></p><p>The following registry overview is a work in progress.</p><p>Further attribute namespaces are currently being migrated and will appear in this registry soon.</p></div><p>Currently, the following namespaces exist:</p><ul><li><a href="./honeyhive.html">Honeyhive</a></li></ul>',10)])])}const b=t(n,[["render",o]]);export{h as __pageData,b as default};
